/// Update the skeleton index file
///
/// Downloads the latest templateflow-skel.zip from GitHub
pub async fn update_skeleton() -> Result<()> {
    let skeleton_path = CONFIG.skeleton_path();
    let skeleton_url = "https://raw.githubusercontent.com/templateflow/python-client/master/templateflow/conf/templateflow-skel.zip";

    // Use download_file with full URL
    let client = reqwest::Client::new();
    let response = client
        .get(skeleton_url)
        .timeout(CONFIG.timeout)
        .send()
        .await
        .map_err(TemplateFlowError::DownloadError)?;

    // Check status
    if !response.status().is_success() {
        return Err(TemplateFlowError::DownloadError(
            reqwest::Error::from(response.error_for_status().unwrap_err())
        ));
    }

    // Get content length for progress bar
    let total_size = response.content_length().unwrap_or(0);

    // Create parent directory if needed
    if let Some(parent) = skeleton_path.parent() {
        std::fs::create_dir_all(parent)?;
    }

    // Create file
    let mut file = File::create(&skeleton_path)?;

    // Create progress bar
    let pb = ProgressBar::new(total_size);
    pb.set_style(
        ProgressStyle::default_bar()
            .template("{msg}\n{spinner:.green} [{elapsed_precise}] [{wide_bar:.cyan/blue}] {bytes}/{total_bytes} ({bytes_per_sec}, {eta})")
            .unwrap()
            .progress_chars("#>-"),
    );
    pb.set_message(format!("Downloading skeleton index"));

    // Stream the response body
    let mut downloaded: u64 = 0;
    let mut stream = response.bytes_stream();

    while let Some(chunk) = stream.next().await {
        let chunk = chunk.map_err(TemplateFlowError::DownloadError)?;
        file.write_all(&chunk)?;
        downloaded += chunk.len() as u64;
        pb.set_position(downloaded);
    }

    pb.finish_with_message("Skeleton index downloaded");

    Ok(())
}

