    assert!(!files.is_empty());

    // Test listing files with a specific query
    let mut query = HashMap::new();
    query.insert("res".to_string(), "01".to_string());
    query.insert("suffix".to_string(), "T1w".to_string());

    let filtered = ls("MNI152NLin2009cAsym", Some(&query)).unwrap();
